    {
      "n": 14,
      "column": "left",
      "text": "Eij jelle/ luhko/ kà ta- winna/ ka wiꞥſch to no\nweem Brahteem klahjahs/ un ka Rohkahm ispestitu/ un f\nLohpineem klahjahs/ un neſs man Tehwain pahrwestu.\nWehſtus atpakkat. Un wiꞥſch\nfuhtija to no Eebrona Eelejas/ un\ntas nahze uhs Sifemu."
    },
    {
      "n": 15,
      "column": "left",
      "text": "Un weens Wihrs atradde\nto/ un raugi/ tas maldijahs Lau-\nká/ tad waizaja to tas Wihrs/\nfazzidams : ko tu mekle?"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Un tas fazzija: es mekle-\njn farws Brahtus/ paſſki man/\nluhdsams/ kur tee ganna?"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Tad fazzija tas Wihrs:\ntee irr no ſchennenes aisgahjuschi/\njo es efmu dsirdejis tohs fakkam:\nEejim uhs Dotamu/ un Jahseps\ngahje faweein Brahteem pakkat/\nun atradde tohs Dotana."
    },
    {
      "n": 18,
      "column": "left",
      "text": "Un tee eerandsija to no tah-\nfenes / un pirns tas tuwaki pee\ntwinneem nahze/ farunnajahs tee\ntwinnu nokaut."
    },
    {
      "n": 19,
      "column": "left",
      "text": "Un fazzija weens uhs oh-\ntrn : Reds/ ſche nahk tas leels\nSapnotajs."
    },
    {
      "n": 20,
      "column": "left",
      "text": "Un nu nahzeet / nokanjam\nmehs to / un eemettam mehs to\nkahda Bedrê/ un fakkam: Kahds\nkauns Swehrs irr to aprihjis/ tad\nredsetim mehs/ kas buhs no win-\nna Sapneem."
    },
    {
      "n": 21,
      "column": "left",
      "text": "Un Rubbens dsirdeja to/\nun ispestija to no winnu Rohkas/\nun fazzija: ne kanjam mehs win-\nnu femmiê."
    },
    {
      "n": 22,
      "column": "left",
      "text": "Wehl fazzija Rubbens us\nteem: Ne iſletieet Affini/ metteet\nfnatu tanni Bedrê/ kas Tukfne-\niir/ un ne peelezeet Rohkas pee"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un kad Jahseps p\nweem Brahteem nahze /\nwilke tee Jahsepam\nSwahrkus/ tohs raibus S\nkus/ kas tam Muggurâ bi"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un nehine to/ un m\nBedrê/ bet ta Bedre bija tu\nun turne bija Uhdens eekſch"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Pehz to apfehda\nMaisi ehft / un pazehle\nAzzis / un skattijahs / un\nweens Ismaëliteru Pulks\nno Gileadas/ un winno Ka\nneffe dahrgas Sahles/Bals\nun Mirres / to nonest u\ngiptu."
    },
    {
      "n": 26,
      "column": "right",
      "text": "Tad fazzija Juhda\nweem Brahteem/ kas mun\nlezz / ja mehs fawu Brah-\nkaujam / un winna Affi-\nſlepjam."
    },
    {
      "n": 27,
      "column": "right",
      "text": "Nahzeet / laid mehs\nnu teem Ismaëliteruem pah-\ndam / un muhſu Rohka\nwinna ne peeſektam/ jo win-\nmuhſu Brahlis/ muhſu M\nun winna Brahti flahtija ta"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Kad nu tee Wihti/ te\ndtjaniteru Prezzineeki fezzen\nje/ iſwilke tee to/ un uſzehle\nsepu no Bedres / un pah-\nJahsepu teem Ismaëliteruem\ndiwidefmits Sudraba - G\nleem / un tee aiſwedde Ja-\nuhs Egiptes-Semmi."
    },
    {
      "n": 29,
      "column": "right",
      "text": "Un Rubbens atgre-\npee tahs Bedres / un red"
    }
  ],
  "confidence": "high",
  "notes": ""
}
